package main

import (
    "fmt"
    "sync"
)

// ---- Shared counter without mutex (race condition) ----
func main() {
    // ---- Without mutex ----
    fmt.Println("=== Without Mutex ===")
    counter := 0
    var wg sync.WaitGroup

    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            counter++  // Race condition!
        }()
    }

    wg.Wait()
    fmt.Printf("Counter without mutex: %d\n", counter)

    // ---- With mutex ----
    fmt.Println("\n=== With Mutex ===")
    var mu sync.Mutex
    safeCounter := 0

    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            mu.Lock()
            safeCounter++
            mu.Unlock()
        }()
    }

    wg.Wait()
    fmt.Printf("Counter with mutex: %d\n", safeCounter)

    // ---- RWMutex ----
    fmt.Println("\n=== RWMutex ===")
    var rwmu sync.RWMutex
    data := 0

    // Multiple readers
    for i := 0; i < 5; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            rwmu.RLock()
            fmt.Printf("Reader: %d\n", data)
            rwmu.RUnlock()
        }()
    }

    // One writer
    wg.Add(1)
    go func() {
        defer wg.Done()
        rwmu.Lock()
        data = 42
        fmt.Println("Writer: set data to 42")
        rwmu.Unlock()
    }()

    wg.Wait()

    // ---- Mutex with defer ----
    fmt.Println("\n=== Mutex with defer ===")
    var mu2 sync.Mutex
    value := 0

    for i := 0; i < 10; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            mu2.Lock()
            defer mu2.Unlock()
            value++
        }()
    }

    wg.Wait()
    fmt.Printf("Value: %d\n", value)
}

